class Book:
    def __init__(self, title, author):
        self.title = title
        self.author = author

    def display(self):
        print(f"Title: {self.title}, Author: {self.author}")

class EBook(Book):
    def __init__(self, title, author, file_size):
        super().__init__(title, author)
        self.file_size = file_size

    def display(self):
        print(f"Title: {self.title}, Author: {self.author}, File Size (MB): {self.file_size}")

book_type = input()
if book_type == 'B':
    title = input()
    author = input()
    book = Book(title, author)
    book.display()
elif book_type == 'E':
    title = input()
    author = input()
    file_size = int(input())
    ebook = EBook(title, author, file_size)
    ebook.display()
